import{_ as a,o as n,c as p,aj as t}from"./chunks/framework.DNJ2HNkG.js";const r=JSON.parse('{"title":"Ubuntu 20.04安装GnuRadio","description":"","frontmatter":{"title":"Ubuntu 20.04安装GnuRadio","date":"2020-09-10T13:23:32.000Z","category":"Radio","tags":["无线","软件无线电"]},"headers":[],"relativePath":"posts/Ubuntu 20.04安装GnuRadio.md","filePath":"posts/Ubuntu 20.04安装GnuRadio.md","lastUpdated":1783047625000}'),e={name:"posts/Ubuntu 20.04安装GnuRadio.md"};function i(l,s,o,d,c,u){return n(),p("div",null,[...s[0]||(s[0]=[t(`<h2 id="_0x01-前言" tabindex="-1">0x01 前言 <a class="header-anchor" href="#_0x01-前言" aria-label="Permalink to &quot;0x01 前言&quot;">​</a></h2><p>因为驱动问题，把新买的联想小新13 Pro锐龙版装了Ubuntu 20.04，用了下感觉还不错，内核升级到5.6.x或者5.7.x，驱动也还行，屏幕亮度那些都能控制，之后就把几台机器的系统都升级到Ubuntu 20.04了。 另外，AMD Yes，四千多买的R7-4800U 16G 512G的配置，性能真没的说，杠杠的！ssd换成1T的后【没舍得上2T/4T】，Win10LTSC/Ubuntu 20.04/Kali/Ubuntu 18.04四系统，很不错。</p><h2 id="_0x02-准备" tabindex="-1">0x02 准备 <a class="header-anchor" href="#_0x02-准备" aria-label="Permalink to &quot;0x02 准备&quot;">​</a></h2><p>Ubuntu 20.04下用root账户挺麻烦的很多程序用起来挺麻烦的，用普通用户更简单点。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo apt-get install git cmake g++ libboost-all-dev libgmp-dev swig python3-numpy \\</span></span>
<span class="line"><span>python3-mako python3-sphinx python3-lxml doxygen libfftw3-dev \\</span></span>
<span class="line"><span>libsdl1.2-dev libgsl-dev libqwt-qt5-dev libqt5opengl5-dev python3-pyqt5 \\</span></span>
<span class="line"><span>liblog4cpp5-dev libzmq3-dev python3-yaml python3-click python3-click-plugins \\</span></span>
<span class="line"><span>python3-zmq python3-scipy python3-gi python3-gi-cairo gobject-introspection gir1.2-gtk-3.0 python3-pip \\</span></span>
<span class="line"><span>gnome-tweak-tool psensor conky</span></span></code></pre></div><p>chrome比较好用，可以装一个</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>wget https://dl.google.com/linux/direct/google-chrome-stable_current_amd64.deb</span></span>
<span class="line"><span>sudo dpkg -i google-chrome-stable_current_amd64.deb</span></span></code></pre></div><p>梯子就不用说了，甚多软件安装都需要</p><h2 id="_0x03-安装" tabindex="-1">0x03 安装 <a class="header-anchor" href="#_0x03-安装" aria-label="Permalink to &quot;0x03 安装&quot;">​</a></h2><p>Ubuntu 20.04用apt安装就是3.8.1，比pybombs省事，所以一般用apt就行了。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo apt-get install hackrf gr-limesdr limesuite bladerf airspy gr-iio rtl-433 rtl-sdr gr-osmosdr gqrx-sdr uhd-soapysdr libuhd-dev gr-radar uhd-host</span></span></code></pre></div><p>还要下载uhd的images，这里没梯子会经常卡住，可以考虑把整个uhd镜像做一个到本地这样比较省事</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>uhd_images_downloader</span></span></code></pre></div><p>安装完成就可以愉快地玩耍了 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Ubuntu_20.04%E5%AE%89%E8%A3%85GNURadio/1599720676979.png" alt=""></p><h2 id="_0x04-工具" tabindex="-1">0x04 工具 <a class="header-anchor" href="#_0x04-工具" aria-label="Permalink to &quot;0x04 工具&quot;">​</a></h2><p>audacity必须的</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo add-apt-repository ppa:ubuntuhandbook1/audacity</span></span>
<span class="line"><span>sudo apt-get update</span></span>
<span class="line"><span>sudo apt-get install audacity</span></span></code></pre></div><p>玩gps的话gps-sdr-sim安一个</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd</span></span>
<span class="line"><span>git clone https://github.com/osqzss/gps-sdr-sim.git</span></span>
<span class="line"><span>cd gps-sdr-sim</span></span>
<span class="line"><span>make</span></span></code></pre></div><p>wireshark需要的话安一个</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo add-apt-repository ppa:wireshark-dev/stable</span></span>
<span class="line"><span>sudo apt-get update</span></span>
<span class="line"><span>sudo apt-get install wireshark</span></span></code></pre></div><p>安装inspectrum和dspectrum</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo apt-get install inspectrum</span></span>
<span class="line"><span>cd</span></span>
<span class="line"><span>git clone https://github.com/tresacton/dspectrum.git</span></span>
<span class="line"><span>cd dspectrum</span></span>
<span class="line"><span>sudo chmod +x ./dspectrum</span></span>
<span class="line"><span>sudo gem install colorize</span></span>
<span class="line"><span>sudo cp ./dspectrum /usr/local/bin/</span></span></code></pre></div><p>安装urh</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd</span></span>
<span class="line"><span>sudo apt-get install python3-numpy python3-psutil python3-zmq python3-pyqt5 g++ libpython3-dev python3-pip cython3</span></span>
<span class="line"><span>sudo python3 -m pip install urh</span></span></code></pre></div>`,25)])])}const g=a(e,[["render",i]]);export{r as __pageData,g as default};
